public static Name getDimensionDisplayValue(RecId _defaultDimension, Name _dimName)
{
    DimensionAttributeValueSetStorage dimStorage;
    DimensionAttributeValue dimAttributeValue;

    dimStorage = DimensionAttributeValueSetStorage::find(_defaultDimension);

    select * from dimAttributeValue 
        where dimAttributeValue.DisplayValue    ==   dimStorage.getDisplayValueByDimensionAttribute(DimensionAttribute::findByName(_dimName).RecId);

    if (dimAttributeValue.getName())
    {
        return dimAttributeValue.getName();
    }
    else
    {
        return dimStorage.getDisplayValueByDimensionAttribute(DimensionAttribute::findByName(_dimName).RecId);
    }



}

public static Name getDimensionDisplayStandardName(RecId _defaultDimension, Name _dimName)
{
    DimensionAttributeValueSetStorage dimStorage;
    DimensionAttributeValue dimAttributeValue;

    dimStorage = DimensionAttributeValueSetStorage::find(_defaultDimension);

    select * from dimAttributeValue
        where dimAttributeValue.DisplayValue    ==   dimStorage.getDisplayValueByDimensionAttribute(DimensionAttribute::findByName(_dimName).RecId);

    return  dimAttributeValue.DisplayValue;


}

public static Name getDimensionDisplayValueName(RecId _defaultDimension, Name _dimName)
{
    DimensionAttributeValueSetStorage dimStorage;
    DimensionAttributeValue dimAttributeValue;

    dimStorage = DimensionAttributeValueSetStorage::find(_defaultDimension);

    select * from dimAttributeValue
        where dimAttributeValue.DisplayValue    ==   dimStorage.getDisplayValueByDimensionAttribute(DimensionAttribute::findByName(_dimName).RecId);


        return dimStorage.getDisplayValueByDimensionAttribute(DimensionAttribute::findByName(_dimName).RecId);




}
